import './TextfieldWithChips.scss';

import { Chip } from ':components/Chip';
import { Icon } from ':components/Icon';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useRef } from 'react';

import type { TextfieldWithChipsProps } from './TextfieldWithChips.types';

export const TextfieldWithChips: React.FC<TextfieldWithChipsProps> = ({
	chips = [],
	dropdownOptions = [],
	value = '',
	onValueChange,
	onChipsChange,
	dropdownFilterFunction = dropdownOptions => dropdownOptions,
	size = 'medium',
	type = 'oneline',
	placeholder,
	disabled = false,
	error,
	helperText,
	label,
	className,
	dataTestId = 'TextfieldWithChips',
}) => {
	const [focusedIndex, setFocusedIndex] = React.useState(-1);
	const textfieldRef = React.useRef(null);
	const [showDropdownMenu, setShowDropdownMenu] = React.useState(false);
	const inputRef = useRef<HTMLInputElement>(null);
	const chipsWithIds = chips.map((chip, index) => ({ label: chip, id: index }));
	const filteredOptions = dropdownFilterFunction(dropdownOptions, value);
	const [isFocused, setIsFocused] = React.useState(false);
	const scrollToInput = () => {
		if (type === 'oneline') {
			setTimeout(() => {
				inputRef.current?.scrollIntoView({
					behavior: 'smooth',
					block: 'end',
				});
			}, 10);
		}
	};

	const handleKeydown = event => {
		scrollToInput();

		switch (event.code) {
			case 'Enter': {
				if (!value) {
					return;
				}
				if (focusedIndex === -1) {
					onNewChip(value);
				} else {
					onNewChip(filteredOptions[focusedIndex]);
				}
				break;
			}
			case 'Backspace': {
				if (value) {
					return;
				}
				onDeleteChip(chipsWithIds.length - 1);
				break;
			}
			case 'ArrowDown': {
				setFocusedIndex(focusedIndex < filteredOptions.length - 1 ? focusedIndex + 1 : focusedIndex);
				break;
			}
			case 'ArrowUp': {
				setFocusedIndex(focusedIndex > 0 ? focusedIndex - 1 : focusedIndex);
				break;
			}
			default: {
				setFocusedIndex(-1);
			}
		}
	};

	const onNewChip = chip => {
		setShowDropdownMenu(false);
		onChipsChange([...chips, chip]);
		scrollToInput();
	};

	const onDeleteChip = index => {
		if (disabled) {
			return;
		}
		setShowDropdownMenu(false);
		onChipsChange(chipsWithIds.filter(chip => chip.id !== index).map(chip => chip.label));
	};

	const handleValueChange = event => {
		const newValue = event.target.value;
		if (newValue.includes(',')) {
			const newChips = newValue.split(',');
			onChipsChange([...chips, ...newChips.slice(0, -1)]);
			onValueChange(newChips.at(-1));
			return;
		}
		setShowDropdownMenu(Boolean(newValue));
		onValueChange(newValue);
	};

	const minifyLabel = (value.length > 0 || chips.length > 0 || isFocused) && label;

	return (
		<div className={'dsb-textfieldwithchips-wrapper'}>
			<label
				className={classNames(
					'dsb-textfieldwithchips__content__label',
					minifyLabel && 'dsb-textfieldwithchips__content__label-small',
				)}
			>
				{label}
			</label>
			<div
				data-testid={dataTestId}
				className={classNames(
					'dsb-textfieldwithchips',
					`dsb-textfieldwithchips-${size}`,
					`dsb-textfieldwithchips-${type}`,
					isFocused && 'dsb-textfieldwithchips-focused',
					disabled && 'dsb-textfieldwithchips-disabled',
					error && 'dsb-textfieldwithchips-error',
					minifyLabel && 'dsb-textfieldwithchips-minifyLabel',
					className,
				)}
				ref={textfieldRef}
				role="button"
				tabIndex={0}
				onClick={() => {
					inputRef.current?.focus();
				}}
				onKeyDown={event => {
					if (event.key === 'Enter' || event.key === ' ') {
						inputRef.current?.focus();
					}
				}}
			>
				<div className={'dsb-textfieldwithchips__content'}>
					{chipsWithIds.map(chip => (
						<Chip
							label={chip.label}
							endAdornment={
								<Icon
									onClick={event => {
										event.stopPropagation();
										onDeleteChip(chip.id);
									}}
									onKeyDown={event => {
										if (event.key === 'Enter' || event.key === ' ') {
											event.stopPropagation();
											onDeleteChip(chip.id);
										}
									}}
									role="button"
									tabIndex={0}
									iconName={Icons.Cancel}
								/>
							}
						/>
					))}
					<input
						ref={inputRef}
						className={'dsb-textfieldwithchips__content__input'}
						value={value}
						onKeyDown={handleKeydown}
						onChange={handleValueChange}
						placeholder={chips.length === 0 && !label && placeholder}
						onFocus={() => {
							setIsFocused(true);
						}}
						onBlur={() => {
							setIsFocused(false);
						}}
						style={{
							width: chips.length === 0 && value.length === 0 ? 'fit-content' : value.length * 10,
						}}
						disabled={disabled}
					/>
				</div>
			</div>

			{showDropdownMenu && !disabled && filteredOptions.length > 0 && (
				<NewDropdownMenu
					handleSetOpen={setShowDropdownMenu}
					onOutsideClick={() => setShowDropdownMenu(false)}
					isOpen={showDropdownMenu}
					targetElement={textfieldRef}
					className={'dsb-textfieldwithchips__dropdown'}
					verticalOffset={1}
				>
					{filteredOptions.map((option, index) => (
						<div
							className={classNames(
								'dsb-textfieldwithchips__dropdown__option',
								index === focusedIndex && 'dsb-textfieldwithchips__dropdown__option-focused',
							)}
							onClick={() => {
								onNewChip(option);
							}}
							onKeyDown={event => {
								if (event.key === 'Enter' || event.key === ' ') {
									onNewChip(option);
								}
							}}
							role="option"
							aria-selected={index === focusedIndex}
							tabIndex={0}
						>
							{option}
						</div>
					))}
				</NewDropdownMenu>
			)}
			<div
				className={classNames(
					'dsb-textfieldwithchips__bottomtext',
					error && 'dsb-textfieldwithchips__bottomtext-error',
				)}
			>
				{helperText}
			</div>
		</div>
	);
};
